                // Verify that boxel_index entries are tombstoned (marked as deleted) for the unpublished realm
                let indexResultsAfter = await dbAdapter.execute(`SELECT * FROM boxel_index WHERE realm_url = '${publishedRealmURL}' AND realm_version = '${realmVersion.current_version}'`);
